function rotateRight(nums, k) {
  const n = nums.length;
  if (n === 0) return nums;

  k %= n;
  if (k === 0) return nums;

  reverse(nums, 0, n - 1);
  reverse(nums, 0, k - 1);
  reverse(nums, k, n - 1);
  return nums;
}

function reverse(arr, left, right) {
  while (left < right) {
    [arr[left], arr[right]] = [arr[right], arr[left]];
    left++;
    right--;
  }
}

