```python
def count_components(n, edges):
    parent = list(range(n))
    rank = [0] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra == rb:
            return 0
        if rank[ra] < rank[rb]:
            parent[ra] = rb
        elif rank[ra] > rank[rb]:
            parent[rb] = ra
        else:
            parent[rb] = ra
            rank[ra] += 1
        return 1

    components = n
    for a, b in edges:
        components -= union(a, b)
    return components
```

Example:
```python
count_components(5, [[0,1],[1,2],[3,4]])  # 2
```

This runs in near-linear time: `O(n + e * α(n))`.

