```js
function parseQueryString(input) {
  if (input == null || input === '') {
    return {};
  }

  if (typeof input !== 'string') {
    throw new TypeError('parseQueryString input must be a string');
  }

  const query = input.startsWith('?') ? input.slice(1) : input;
  if (query === '') {
    return {};
  }

  const result = {};

  const safeDecode = (value) => {
    const normalized = value.replace(/\+/g, ' ');
    try {
      return decodeURIComponent(normalized);
    } catch {
      return normalized;
    }
  };

  for (const part of query.split('&')) {
    if (part === '') {
      continue;
    }

    const eqIndex = part.indexOf('=');
    const rawKey = eqIndex === -1 ? part : part.slice(0, eqIndex);
    const rawValue = eqIndex === -1 ? '' : part.slice(eqIndex + 1);

    const key = safeDecode(rawKey);
    const value = safeDecode(rawValue);

    if (Object.prototype.hasOwnProperty.call(result, key)) {
      const current = result[key];
      result[key] = Array.isArray(current) ? [...current, value] : [current, value];
    } else {
      result[key] = value;
    }
  }

  return result;
}

module.exports = { parseQueryString };
```

