```js
const assert = require('assert');

function isPlainObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function cloneValue(value) {
  if (Array.isArray(value)) {
    return value.map(cloneValue);
  }
  if (isPlainObject(value)) {
    const copy = {};
    for (const key of Object.keys(value)) {
      copy[key] = cloneValue(value[key]);
    }
    return copy;
  }
  return value;
}

function deepMerge(a, b) {
  if (!isPlainObject(a) || !isPlainObject(b)) {
    throw new TypeError('deepMerge expects two plain objects');
  }

  const result = {};
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);

  for (const key of keys) {
    const aHasKey = Object.prototype.hasOwnProperty.call(a, key);
    const bHasKey = Object.prototype.hasOwnProperty.call(b, key);

    if (!bHasKey) {
      result[key] = cloneValue(a[key]);
      continue;
    }

    if (!aHasKey) {
      result[key] = cloneValue(b[key]);
      continue;
    }

    const aValue = a[key];
    const bValue = b[key];

    if (isPlainObject(aValue) && isPlainObject(bValue)) {
      result[key] = deepMerge(aValue, bValue);
    } else {
      result[key] = cloneValue(bValue);
    }
  }

  return result;
}

// 1. merges top-level keys
assert.deepStrictEqual(
  deepMerge({ a: 1 }, { b: 2 }),
  { a: 1, b: 2 }
);

// 2. merges nested objects recursively
assert.deepStrictEqual(
  deepMerge({ a: { x: 1 } }, { a: { y: 2 } }),
  { a: { x: 1, y: 2 } }
);

// 3. b overwrites primitive in a
assert.deepStrictEqual(
  deepMerge({ a: 1 }, { a: 2 }),
  { a: 2 }
);

// 4. arrays are overwritten, not merged
assert.deepStrictEqual(
  deepMerge({ a: [1, 2], keep: true }, { a: [3] }),
  { a: [3], keep: true }
);

// 5. null overwrites object
assert.deepStrictEqual(
  deepMerge({ a: { x: 1 } }, { a: null }),
  { a: null }
);

// 6. object overwrites null
assert.deepStrictEqual(
  deepMerge({ a: null }, { a: { x: 1 } }),
  { a: { x: 1 } }
);

// 7. missing keys are preserved from a
assert.deepStrictEqual(
  deepMerge({ a: 1, b: 2 }, { b: 3 }),
  { a: 1, b: 3 }
);

// 8. empty objects merge correctly
assert.deepStrictEqual(
  deepMerge({}, {}),
  {}
);

// 9. conflicting primitive types are overwritten by b
assert.deepStrictEqual(
  deepMerge({ a: '1' }, { a: false }),
  { a: false }
);

// 10. deep nesting works
assert.deepStrictEqual(
  deepMerge(
    { a: { b: { c: { d: 1 } } } },
    { a: { b: { c: { e: 2 } } } }
  ),
  { a: { b: { c: { d: 1, e: 2 } } } }
);

// 11. does not mutate input objects
const inputA = { a: { x: 1 }, arr: [1, 2] };
const inputB = { a: { y: 2 }, arr: [3] };
const merged = deepMerge(inputA, inputB);
merged.a.x = 99;
merged.arr.push(4);
assert.deepStrictEqual(inputA, { a: { x: 1 }, arr: [1, 2] });
assert.deepStrictEqual(inputB, { a: { y: 2 }, arr: [3] });

// 12. clones nested values from keys present in only one input
const onlyInA = { a: { nested: { v: 1 } } };
const result = deepMerge(onlyInA, {});
result.a.nested.v = 42;
assert.deepStrictEqual(onlyInA, { a: { nested: { v: 1 } } });

// 13. rejects non-plain-object inputs
assert.throws(() => deepMerge(null, {}), TypeError);
assert.throws(() => deepMerge({}, []), TypeError);

console.log('All tests passed');
```

Behavior: plain objects merge recursively; arrays are replaced by `b` rather than concatenated or merged element-wise; all other values, including `null`, are overwritten by `b` when the key exists in both objects.

