/**
 * Normalize a user-entered phone number into a simplified E.164-like format.
 *
 * Format:
 * - `+<countrycode><nationalnumber>`
 * - Optional extension appended as ` x<digits>`
 *
 * Assumptions:
 * - `defaultCountry` must be a numeric country calling code string/number like `1`, `44`, `33`.
 * - If `input` starts with `+`, `00`, or `011`, it is treated as already international.
 * - Otherwise, the number is treated as local and `defaultCountry` is prepended.
 * - Formatting punctuation and whitespace are ignored.
 * - Extensions are recognized from `ext`, `ext.`, or `x` followed by digits.
 * - Alphabetic characters in the main number are rejected rather than converted from vanity format.
 * - Empty/blank input and numbers with fewer than 4 digits after normalization are invalid.
 */
function normalizePhoneNumber(input, defaultCountry) {
  if (input == null) {
    throw new Error('Phone number is required');
  }

  const raw = String(input).trim();
  if (!raw) {
    throw new Error('Phone number is required');
  }

  const country = String(defaultCountry ?? '').trim();
  if (!/^\d{1,3}$/.test(country)) {
    throw new Error('defaultCountry must be a 1-3 digit country calling code');
  }

  const extMatch = raw.match(/(?:ext\.?|x)\s*(\d+)\s*$/i);
  const extension = extMatch ? extMatch[1] : '';
  const mainPart = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[A-Za-z]/.test(mainPart)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalizedMain = mainPart.replace(/[\s().-]/g, '');

  if (!/^\+?\d+$/.test(normalizedMain) && !/^(?:00|011)\d+$/.test(normalizedMain)) {
    throw new Error('Phone number contains invalid characters');
  }

  if (normalizedMain.startsWith('+')) {
    normalizedMain = normalizedMain;
  } else if (normalizedMain.startsWith('00')) {
    normalizedMain = `+${normalizedMain.slice(2)}`;
  } else if (normalizedMain.startsWith('011')) {
    normalizedMain = `+${normalizedMain.slice(3)}`;
  } else {
    normalizedMain = `+${country}${normalizedMain}`;
  }

  const digitsOnly = normalizedMain.slice(1);
  if (!/^\d+$/.test(digitsOnly) || digitsOnly.length < 4 || digitsOnly.length > 15) {
    throw new Error('Phone number is not a valid length');
  }

  return extension ? `${normalizedMain} x${extension}` : normalizedMain;
}

module.exports = { normalizePhoneNumber };
