function unflattenObject(obj) {
  if (obj == null || typeof obj !== 'object' || Array.isArray(obj)) {
    throw new TypeError('Expected a plain object');
  }

  const result = {};

  for (const [flatKey, value] of Object.entries(obj)) {
    if (typeof flatKey !== 'string' || flatKey.length === 0) {
      throw new Error(`Invalid key: ${String(flatKey)}`);
    }

    const parts = flatKey.split('.');

    if (parts.some(part => part.length === 0)) {
      throw new Error(`Invalid key with empty segment: ${flatKey}`);
    }

    let current = result;

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      const isLeaf = i === parts.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(current, part) &&
          current[part] != null &&
          typeof current[part] === 'object'
        ) {
          throw new Error(`Conflicting path: ${flatKey}`);
        }

        current[part] = value;
        continue;
      }

      if (!Object.prototype.hasOwnProperty.call(current, part)) {
        current[part] = {};
      } else if (current[part] == null || typeof current[part] !== 'object' || Array.isArray(current[part])) {
        throw new Error(`Conflicting path: ${flatKey}`);
      }

      current = current[part];
    }
  }

  return result;
}

module.exports = { unflattenObject };
