function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('parseCsvLine expects a string');
  }

  if (line === '') {
    return [''];
  }

  const fields = [];
  let field = '';
  let inQuotes = false;
  let wasQuotedField = false;

  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];

    if (inQuotes) {
      if (char === '"') {
        if (line[i + 1] === '"') {
          field += '"';
          i += 1;
        } else {
          inQuotes = false;
          wasQuotedField = true;
        }
      } else {
        field += char;
      }
      continue;
    }

    if (char === ',') {
      fields.push(field);
      field = '';
      wasQuotedField = false;
      continue;
    }

    if (char === '"') {
      if (field.length === 0) {
        inQuotes = true;
        wasQuotedField = false;
        continue;
      }
      throw new Error(`Malformed CSV line: unexpected quote at position ${i}`);
    }

    if (wasQuotedField) {
      throw new Error(`Malformed CSV line: unexpected character after closing quote at position ${i}`);
    }

    field += char;
  }

  if (inQuotes) {
    throw new Error('Malformed CSV line: unmatched quote');
  }

  fields.push(field);
  return fields;
}

module.exports = { parseCsvLine };
```

