      expected: [0, 3],
    },
    {
      name: 'empty array',
      nums: [],
      target: 1,
      expected: [-1, -1],
    },
    {
      name: 'single-element array hit',
      nums: [5],
      target: 5,
      expected: [0, 0],
    },
    {
      name: 'single-element array miss',
      nums: [5],
      target: 1,
      expected: [-1, -1],
    },
    {
      name: 'duplicates at ends',
      nums: [2, 2, 2, 3, 4, 5, 5, 5],
      target: 5,
      expected: [5, 7],
    },
    {
      name: 'negative numbers',
      nums: [-10, -5, -5, -5, -1, 0, 3],
      target: -5,
      expected: [1, 3],
    },
    {
      name: 'target at beginning',
      nums: [1, 1, 1, 2, 3, 4],
      target: 1,
      expected: [0, 2],
    },
    {
      name: 'large sorted input',
      nums: Array.from({ length: 100000 }, (_, i) => Math.floor(i / 3)),
      target: 12345,
      expected: [37035, 37037],
    },
  ];

  for (const { name, nums, target, expected } of tests) {
    const actual = binarySearchRange(nums, target);
    const pass = actual[0] === expected[0] && actual[1] === expected[1];
    console.assert(
