```js
function memoize(fn) {
  if (typeof fn !== 'function') {
    throw new TypeError('memoize expected a function');
  }

  const root = new Map();
  const RESULT = Symbol('result');
  const ERROR = Symbol('error');

  return function memoized(...args) {
    let node = root;

    for (const arg of args) {
      const isObjectKey = arg !== null && (typeof arg === 'object' || typeof arg === 'function');
      const storeKey = isObjectKey ? 'object' : 'primitive';

      if (!node.has(storeKey)) {
        node.set(storeKey, isObjectKey ? new WeakMap() : new Map());
      }

      const store = node.get(storeKey);

      if (!store.has(arg)) {
        store.set(arg, new Map());
      }

      node = store.get(arg);
    }

    if (node.has(ERROR)) {
      throw node.get(ERROR);
    }

    if (node.has(RESULT)) {
      return node.get(RESULT);
    }

    try {
      const value = fn.apply(this, args);
      node.set(RESULT, value);
      return value;
    } catch (error) {
      node.set(ERROR, error);
      throw error;
    }
  };
}
```

