  let calls = 0;
  const add = memoize((a, b) => {
    calls += 1;
    return a + b;
  });

  assert.equal(add(1, 2), 3);
  assert.equal(add(1, 2), 3);
  assert.equal(calls, 1);
});

test('treats different primitive values as different keys', () => {
