    return obj.value * 2;
  });

  const a = { value: 2 };
  const b = { value: 2 };

  assert.equal(fn(a), 4);
  assert.equal(fn(a), 4);
  assert.equal(fn(b), 4);
  assert.equal(calls, 2);
});

test('distinguishes argument order', () => {
