  const pair = memoize((a, b) => {
    calls += 1;
    return `${a}:${b}`;
  });

  assert.equal(pair('x', 'y'), 'x:y');
  assert.equal(pair('y', 'x'), 'y:x');
  assert.equal(pair('x', 'y'), 'x:y');
  assert.equal(calls, 2);
});

test('supports zero-argument functions', () => {
  let calls = 0;
  const fn = memoize(() => {
    calls += 1;
    return 42;
  });

  assert.equal(fn(), 42);
  assert.equal(fn(), 42);
  assert.equal(calls, 1);
});

test('caches undefined results', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls += 1;
    if (x > 0) return undefined;
    return 'nope';
  });

  assert.equal(fn(1), undefined);
  assert.equal(fn(1), undefined);
  assert.equal(calls, 1);
});

test('caches thrown errors for the same arguments', () => {
  let calls = 0;
  const error = new Error('boom');
  const fn = memoize((x) => {
    calls += 1;
    if (x === 1) throw error;
    return x;
  });

  assert.throws(() => fn(1), /boom/);
  assert.throws(() => fn(1), /boom/);
  assert.equal(calls, 1);
});

test('preserves this for uncached calls', () => {
  const obj = {
    factor: 3,
    multiply: memoize(function (x) {
      return x * this.factor;
    }),
  };

  assert.equal(obj.multiply(4), 12);
});

test('cache is based only on arguments, not this binding', () => {
  let calls = 0;
  const fn = memoize(function (x) {
    calls += 1;
    return x * this.factor;
  });

  const a = { factor: 2, fn };
  const b = { factor: 10, fn };

  assert.equal(a.fn(5), 10);
  assert.equal(b.fn(5), 10);
  assert.equal(calls, 1);
});
```

**Cache key strategy**
- Use a nested trie of caches, one level per argument.
- For primitives, use `Map` so values like `1`, `'1'`, `undefined`, and `NaN` are handled correctly.
- For objects/functions, use `WeakMap` keyed by reference identity.
- This avoids fragile stringification and preserves argument order naturally.
- `this` is preserved when computing via `fn.apply(this, args)`, but it is **not** part of the cache key in this implementation. If you need per-receiver caching, include `this` as an extra first key.

