function slugify(input) {
  if (input == null) return "";

  const transliterationMap = {
    ß: "ss",
    Æ: "AE",
    æ: "ae",
    Ø: "O",
    ø: "o",
    Å: "A",
    å: "a",
    Þ: "TH",
    þ: "th",
    Đ: "D",
    đ: "d",
    Ł: "L",
    ł: "l",
    Œ: "OE",
    œ: "oe",
  };

  const transliterated = String(input)
    .replace(/[ßÆæØøÅåÞþĐđŁłŒœ]/g, (char) => transliterationMap[char] || char)
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "");

  return transliterated
    .toLowerCase()
    .replace(/['’]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-+/g, "-");
}

module.exports = { slugify };
```

