function compareVersions(a, b) {
  const parse = (value) => {
    if (typeof value !== 'string') {
      throw new TypeError('Version must be a string');
    }

    const input = value.trim();
    if (!input) {
      throw new Error('Invalid version: empty string');
    }

    const match = input.match(/^(\d+(?:\.\d+)*)(?:-([0-9A-Za-z.-]+))?$/);
    if (!match) {
      throw new Error(`Invalid version: ${value}`);
    }

    const core = match[1].split('.');
    const prerelease = match[2] ? match[2].split('.') : [];

    const nums = core.map((segment) => {
      if (!/^\d+$/.test(segment)) {
        throw new Error(`Invalid version: ${value}`);
      }
      return Number(segment);
    });

    if (prerelease.some((part) => part.length === 0)) {
      throw new Error(`Invalid version: ${value}`);
    }

    return { nums, prerelease };
  };

  const pa = parse(a);
  const pb = parse(b);
  const maxLen = Math.max(pa.nums.length, pb.nums.length);

  for (let i = 0; i < maxLen; i++) {
    const na = pa.nums[i] ?? 0;
    const nb = pb.nums[i] ?? 0;
    if (na < nb) return -1;
    if (na > nb) return 1;
  }

  const aHasPre = pa.prerelease.length > 0;
  const bHasPre = pb.prerelease.length > 0;

  if (!aHasPre && !bHasPre) return 0;
  if (!aHasPre) return 1;
  if (!bHasPre) return -1;

  const preLen = Math.max(pa.prerelease.length, pb.prerelease.length);
  for (let i = 0; i < preLen; i++) {
    const xa = pa.prerelease[i];
    const xb = pb.prerelease[i];

    if (xa === undefined) return -1;
    if (xb === undefined) return 1;

    const aNum = /^\d+$/.test(xa);
    const bNum = /^\d+$/.test(xb);

    if (aNum && bNum) {
      const na = Number(xa);
      const nb = Number(xb);
      if (na < nb) return -1;
      if (na > nb) return 1;
      continue;
    }

    if (aNum && !bNum) return -1;
    if (!aNum && bNum) return 1;

    if (xa < xb) return -1;
    if (xa > xb) return 1;
  }

  return 0;
}

module.exports = { compareVersions };
```

