function humanFileSize(value) {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    throw new TypeError('bytes must be a finite number');
  }

  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB'];
  const negative = value < 0;
  let bytes = Math.abs(value);

  if (bytes === 0) return '0 B';

  let unitIndex = 0;
  while (bytes >= 1024 && unitIndex < units.length - 1) {
    bytes /= 1024;
    unitIndex++;
  }

  const formatted = Number.isInteger(bytes)
    ? String(bytes)
    : bytes >= 10
      ? bytes.toFixed(1).replace(/\.0$/, '')
      : bytes.toFixed(1).replace(/\.0$/, '');

  return `${negative ? '-' : ''}${formatted} ${units[unitIndex]}`;
}

// Tests (Node.js assert)
