assert.strictEqual(humanFileSize(0), '0 B');
assert.strictEqual(humanFileSize(1), '1 B');
assert.strictEqual(humanFileSize(1023), '1023 B');
assert.strictEqual(humanFileSize(1024), '1 KB');
assert.strictEqual(humanFileSize(1536), '1.5 KB');
assert.strictEqual(humanFileSize(1048576), '1 MB');
assert.strictEqual(humanFileSize(1073741824), '1 GB');
assert.strictEqual(humanFileSize(1024 ** 4 * 1.5), '1.5 TB');
assert.strictEqual(humanFileSize(-1536), '-1.5 KB');
assert.strictEqual(humanFileSize(0.5), '0.5 B');
assert.strictEqual(humanFileSize(1024 ** 2 - 1), '1024 KB');
