function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new TypeError('maxWidth must be a positive integer');
  }
  if (typeof text !== 'string') {
    throw new TypeError('text must be a string');
  }
  if (text.length === 0) {
    return '';
  }

  const paragraphs = text.split('\n');
  const wrapped = paragraphs.map(wrapParagraph);
  return wrapped.join('\n');

  function wrapParagraph(paragraph) {
    if (paragraph === '') {
      return '';
    }

    const hasTrailingWhitespace = /\s+$/.test(paragraph);
    const words = paragraph.trim().split(/\s+/).filter(Boolean);

    if (words.length === 0) {
      return '';
    }

    const lines = [];
    let current = '';

    for (const word of words) {
      if (word.length > maxWidth) {
        if (current) {
          lines.push(current);
          current = '';
        }
        for (let i = 0; i < word.length; i += maxWidth) {
          lines.push(word.slice(i, i + maxWidth));
        }
        continue;
      }

      if (!current) {
        current = word;
        continue;
      }

      if (current.length + 1 + word.length <= maxWidth) {
        current += ' ' + word;
      } else {
        lines.push(current);
        current = word;
      }
    }

    if (current) {
      lines.push(current);
    }

    if (hasTrailingWhitespace && lines.length > 0) {
      const last = lines[lines.length - 1];
      if (last.length < maxWidth) {
        lines[lines.length - 1] = last + ' ';
      } else {
        lines.push(' ');
      }
    }

    return lines.join('\n');
  }
}

module.exports = { wordWrap };
```

