```js
function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const childrenByParent = new Map();
  const roots = [];

  for (let i = 0; i < items.length; i++) {
    const item = items[i];

    if (!item || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    if (!Object.prototype.hasOwnProperty.call(item, 'id')) {
      throw new Error(`items[${i}] is missing id`);
    }

    const { id, parentId } = item;

    if (id === null || id === undefined) {
      throw new Error(`items[${i}] has invalid id`);
    }

    if (nodes.has(id)) {
      throw new Error(`duplicate id: ${id}`);
    }

    const node = { ...item, children: [] };
    nodes.set(id, node);

    if (!childrenByParent.has(parentId)) {
      childrenByParent.set(parentId, []);
    }
    childrenByParent.get(parentId).push(node);
  }

  for (const node of nodes.values()) {
    if (node.parentId == null) {
      roots.push(node);
      continue;
    }

    const parent = nodes.get(node.parentId);
    if (!parent) {
      throw new Error(`missing parent: ${node.parentId} for id: ${node.id}`);
    }

    parent.children.push(node);
  }

  const visiting = new Set();
  const visited = new Set();

  function visit(node) {
    if (visited.has(node.id)) return;
    if (visiting.has(node.id)) {
      throw new Error(`cycle detected at id: ${node.id}`);
    }

    visiting.add(node.id);
    for (const child of node.children) {
      visit(child);
    }
    visiting.delete(node.id);
    visited.add(node.id);
  }

  for (const node of nodes.values()) {
    visit(node);
  }

  return roots;
}

module.exports = { buildTree };
```

