function parseDateISO(input) {
  if (typeof input !== 'string') {
    return { ok: false, error: 'Input must be a string' };
  }

  if (input !== input.trim() || input === '') {
    return { ok: false, error: 'Date must be a non-empty trimmed string in YYYY-MM-DD format' };
  }

  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(input);
  if (!match) {
    return { ok: false, error: 'Date must match YYYY-MM-DD' };
  }

  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);

  if (month < 1 || month > 12) {
    return { ok: false, error: 'Month must be between 01 and 12' };
  }

  const isLeapYear =
    (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;

  const daysInMonth = [
    31,
    isLeapYear ? 29 : 28,
    31,
    30,
    31,
    30,
    31,
    31,
    30,
    31,
    30,
    31,
  ];

  if (day < 1 || day > daysInMonth[month - 1]) {
    return { ok: false, error: 'Day is out of range for month' };
  }

  return {
    ok: true,
    year,
    month,
    day,
    date: new Date(Date.UTC(year, month - 1, day)),
  };
}
