function relativePath(from, to) {
  if (typeof from !== 'string' || typeof to !== 'string') {
    throw new TypeError('from and to must be strings');
  }

  const normalize = (input) => {
    if (input.length === 0) {
      throw new TypeError('path must be a non-empty absolute path');
    }

    const unified = input.replace(/\\/g, '/');
    const isAbsolute = unified.startsWith('/');
    if (!isAbsolute) {
      throw new TypeError('path must be absolute');
    }

    const parts = unified.split('/').filter(Boolean);
    return parts;
  };

  const fromParts = normalize(from);
  const toParts = normalize(to);

  let shared = 0;
  while (
    shared < fromParts.length &&
    shared < toParts.length &&
    fromParts[shared] === toParts[shared]
  ) {
    shared++;
  }

  const up = new Array(fromParts.length - shared).fill('..');
  const down = toParts.slice(shared);
  const result = [...up, ...down].join('/');

  return result || '.';
}

// tests
const tests = [
  {
    name: 'same path',
    from: '/a/b/c',
    to: '/a/b/c',
    expected: '.',
  },
  {
    name: 'sibling directories',
    from: '/a/b/c',
    to: '/a/b/d',
    expected: '../d',
  },
  {
    name: 'nested target deeper',
    from: '/a/b',
    to: '/a/b/c/d',
    expected: 'c/d',
  },
  {
    name: 'nested target higher',
    from: '/a/b/c/d',
    to: '/a/b',
    expected: '../..',
  },
  {
    name: 'from root to nested path',
    from: '/',
    to: '/a/b',
    expected: 'a/b',
  },
  {
    name: 'to root from nested path',
    from: '/a/b',
    to: '/',
    expected: '../..',
  },
  {
    name: 'trailing slashes ignored',
    from: '/a/b/',
    to: '/a/b/c/',
    expected: 'c',
  },
  {
    name: 'mixed separators supported',
    from: '\\a\\b\\c',
    to: '\\a\\d\\e',
    expected: '../../d/e',
  },
  {
    name: 'invalid non-absolute from',
    from: 'a/b',
    to: '/a/b',
    error: 'path must be absolute',
  },
  {
    name: 'invalid non-absolute to',
    from: '/a/b',
    to: 'a/b',
    error: 'path must be absolute',
  },
];

for (const test of tests) {
  try {
    const actual = relativePath(test.from, test.to);
    if ('error' in test) {
      throw new Error(`${test.name}: expected error ${test.error}`);
    }
    if (actual !== test.expected) {
      throw new Error(`${test.name}: expected ${test.expected}, got ${actual}`);
    }
  } catch (err) {
    if (!('error' in test)) {
      throw err;
    }
    if (err.message !== test.error) {
      throw new Error(`${test.name}: expected error ${test.error}, got ${err.message}`);
    }
  }
}

console.log('All tests passed');
```

Notes:
- Returns `.` when both paths are the same.
- Normalizes `\\` to `/`, so mixed separators are supported in a POSIX-style way.
- Treats trailing slashes as insignificant.
- Throws `TypeError` for non-string, empty, or non-absolute input.

