function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }
  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }
  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const normalizedRules = rules.map((rule, index) => {
    if (!rule || typeof rule !== 'object') {
      throw new TypeError(`rules[${index}] must be an object`);
    }

    const key = rule.key;
    const direction = rule.direction ?? 'asc';

    if (typeof key !== 'string' || key.length === 0) {
      throw new TypeError(`rules[${index}].key must be a non-empty string`);
    }
    if (direction !== 'asc' && direction !== 'desc') {
      throw new TypeError(`rules[${index}].direction must be "asc" or "desc"`);
    }

    return { key, direction };
  });

  return items
    .map((item, index) => ({ item, index }))
    .sort((a, b) => {
      for (const rule of normalizedRules) {
        const av = a.item?.[rule.key];
        const bv = b.item?.[rule.key];
        const comparison = compareValues(av, bv);

        if (comparison !== 0) {
          return rule.direction === 'desc' ? -comparison : comparison;
        }
      }

      return a.index - b.index;
    })
    .map((entry) => entry.item);
}

function compareValues(a, b) {
  if (a === b) {
    return 0;
  }

  const aMissing = a == null;
  const bMissing = b == null;

  if (aMissing && bMissing) {
    return 0;
  }
  if (aMissing) {
    return 1;
  }
  if (bMissing) {
    return -1;
  }

  const ta = typeof a;
  const tb = typeof b;

  if (ta === tb) {
    if (ta === 'number') {
      if (Number.isNaN(a) && Number.isNaN(b)) return 0;
      if (Number.isNaN(a)) return 1;
      if (Number.isNaN(b)) return -1;
      return a < b ? -1 : 1;
    }

    if (ta === 'string' || ta === 'boolean' || ta === 'bigint') {
      return a < b ? -1 : 1;
    }
  }

  const rankA = typeRank(a);
  const rankB = typeRank(b);

  if (rankA !== rankB) {
    return rankA - rankB;
  }

  const sa = String(a);
  const sb = String(b);
  return sa < sb ? -1 : sa > sb ? 1 : 0;
}

function typeRank(value) {
  switch (typeof value) {
    case 'number':
      return 0;
    case 'bigint':
      return 1;
    case 'string':
      return 2;
    case 'boolean':
      return 3;
    case 'object':
      return 4;
    case 'symbol':
      return 5;
    case 'function':
      return 6;
    case 'undefined':
      return 7;
    default:
      return 8;
  }
}

module.exports = { sortByMultiple, compareValues };
