function serializeForm(fields) {
  if (!Array.isArray(fields) || fields.length === 0) return '';

  return fields
    .filter((field) => field && Object.prototype.hasOwnProperty.call(field, 'name'))
    .map(({ name, value }) => {
      const encodedName = encodeURIComponent(String(name));
      const encodedValue = value == null ? '' : encodeURIComponent(String(value));
      return `${encodedName}=${encodedValue}`;
    })
    .join('&');
}

module.exports = { serializeForm };
