function removeComments(code) {
  let result = '';
  let i = 0;
  let state = 'code';
  let quote = '';

  while (i < code.length) {
    const ch = code[i];
    const next = code[i + 1];

    if (state === 'code') {
      if ((ch === '"' || ch === "'" || ch === '`')) {
        quote = ch;
        state = 'string';
        result += ch;
        i += 1;
        continue;
      }

      if (ch === '/' && next === '/') {
        i += 2;
        while (i < code.length && code[i] !== '\n') {
          i += 1;
        }
        continue;
      }

      if (ch === '/' && next === '*') {
        i += 2;
        while (i < code.length && !(code[i] === '*' && code[i + 1] === '/')) {
          i += 1;
        }
        if (i < code.length) {
          i += 2;
        }
        continue;
      }

      result += ch;
      i += 1;
      continue;
    }

    if (state === 'string') {
      result += ch;

      if (ch === '\\') {
        if (i + 1 < code.length) {
          result += code[i + 1];
          i += 2;
        } else {
          i += 1;
        }
        continue;
      }

      if (ch === quote) {
        state = 'code';
        quote = '';
      }

      i += 1;
    }
  }

  return result;
}

module.exports = { removeComments };
