function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (!s) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const roman = s.toUpperCase();
  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };

  const subtractives = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);
  const nonRepeatable = new Set(['V', 'L', 'D']);

  let total = 0;
  let repeatCount = 1;

  for (let i = 0; i < roman.length; i++) {
    const curr = roman[i];
    const next = roman[i + 1];
    const currVal = values[curr];
    const nextVal = next ? values[next] : 0;

    if (i > 0) {
      if (roman[i] === roman[i - 1]) {
        repeatCount += 1;
      } else {
        repeatCount = 1;
      }

      if (nonRepeatable.has(curr) && repeatCount > 1) {
        throw new Error(`Symbol ${curr} cannot repeat`);
      }
      if (!nonRepeatable.has(curr) && repeatCount > 3) {
        throw new Error(`Symbol ${curr} cannot repeat more than 3 times`);
      }
    }

    if (next && currVal < nextVal) {
      const pair = curr + next;

      if (!subtractives.has(pair)) {
        throw new Error(`Invalid subtractive pattern: ${pair}`);
      }
      if (repeatCount > 1) {
        throw new Error(`Invalid repeated symbol before subtractive pair: ${pair}`);
      }

      total += nextVal - currVal;
      i += 1;
      repeatCount = 1;
      continue;
    }

    total += currVal;
  }

  const intToRoman = (num) => {
    const table = [
      [1000, 'M'],
      [900, 'CM'],
      [500, 'D'],
      [400, 'CD'],
      [100, 'C'],
      [90, 'XC'],
      [50, 'L'],
      [40, 'XL'],
      [10, 'X'],
      [9, 'IX'],
      [5, 'V'],
      [4, 'IV'],
      [1, 'I'],
    ];

    let result = '';
    for (const [value, symbol] of table) {
      while (num >= value) {
        result += symbol;
        num -= value;
      }
    }
    return result;
  };

  if (intToRoman(total) !== roman) {
    throw new Error('Malformed Roman numeral');
  }

  return total;
}

