function knapsack01(items, capacity) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Number.isInteger(capacity) || capacity < 0) {
    throw new TypeError('capacity must be a non-negative integer');
  }

  for (let i = 0; i < items.length; i += 1) {
    const item = items[i];

    if (
      item === null ||
      typeof item !== 'object' ||
      !Number.isInteger(item.weight) ||
      item.weight < 0 ||
      typeof item.value !== 'number' ||
      !Number.isFinite(item.value)
    ) {
      throw new TypeError(
        `items[${i}] must be an object with a non-negative integer weight and a finite numeric value`
      );
    }
  }

  const dp = Array(capacity + 1).fill(0);

  for (const { weight, value } of items) {
    for (let c = capacity; c >= weight; c -= 1) {
      dp[c] = Math.max(dp[c], dp[c - weight] + value);
    }
  }

  return dp[capacity];
}

module.exports = { knapsack01 };
```

