604.answer:
```python
from dataclasses import dataclass
from typing import Any, Dict, Iterable, List, Tuple


@dataclass
class ProcessResult:
    saved: int
    errors: List[str]
    report: Dict[str, Any]


def process_items(items: Iterable[Dict[str, Any]], repository, reporter) -> ProcessResult:
    normalized_items = normalize_items(items)
    validated_items, errors = validate_items(normalized_items)
    saved_count = persist_items(validated_items, repository)
    report = build_report(items=validated_items, saved_count=saved_count, errors=errors, reporter=reporter)
    return ProcessResult(saved=saved_count, errors=errors, report=report)


def normalize_items(items: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
    normalized = []
    for item in items:
        normalized.append(normalize_item(item))
    return normalized


def normalize_item(item: Dict[str, Any]) -> Dict[str, Any]:
    return {
        **item,
        "name": item.get("name", "").strip(),
        "email": item.get("email", "").strip().lower(),
    }


def validate_items(items: Iterable[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], List[str]]:
    valid_items = []
    errors = []

    for item in items:
        error = validate_item(item)
        if error:
            errors.append(error)
            continue
        valid_items.append(item)

    return valid_items, errors


def validate_item(item: Dict[str, Any]) -> str | None:
    if not item["name"]:
        return f"Missing name for item: {item}"
    if "@" not in item["email"]:
        return f"Invalid email for item: {item}"
    return None


def persist_items(items: Iterable[Dict[str, Any]], repository) -> int:
    saved_count = 0
    for item in items:
        repository.save(item)
        saved_count += 1
    return saved_count


def build_report(*, items: Iterable[Dict[str, Any]], saved_count: int, errors: List[str], reporter) -> Dict[str, Any]:
    report = {
        "processed": len(list(items)) if not isinstance(items, list) else len(items),
        "saved": saved_count,
        "errors": errors,
        "success": not errors,
    }
    reporter.send(report)
    return report
