```ts
import crypto from 'node:crypto';
import express from 'express';

type VerifyResult =
  | { ok: true; eventId?: string; timestamp?: number }
  | { ok: false; reason: 'missing_headers' | 'invalid_timestamp' | 'timestamp_skew' | 'invalid_signature' | 'replay' };

interface ReplayStore {
  has(key: string): Promise<boolean>;
  set(key: string, ttlSeconds: number): Promise<void>;
}

class InMemoryReplayStore implements ReplayStore {
  private readonly seen = new Map<string, number>();

  async has(key: string): Promise<boolean> {
    const now = Date.now();
    const expiresAt = this.seen.get(key);
    if (!expiresAt) return false;
    if (expiresAt <= now) {
      this.seen.delete(key);
      return false;
    }
    return true;
  }

  async set(key: string, ttlSeconds: number): Promise<void> {
    this.seen.set(key, Date.now() + ttlSeconds * 1000);
  }
}

interface WebhookVerifierOptions {
  currentSecret: string;
  previousSecret?: string;
  maxSkewSeconds?: number;
  replayTtlSeconds?: number;
  replayStore?: ReplayStore;
  headerNames?: {
    signature?: string;
    timestamp?: string;
    eventId?: string;
  };
}

class WebhookVerifier {
  private readonly currentSecret: string;
  private readonly previousSecret?: string;
  private readonly maxSkewSeconds: number;
  private readonly replayTtlSeconds: number;
  private readonly replayStore: ReplayStore;
  private readonly headers: Required<NonNullable<WebhookVerifierOptions['headerNames']>>;

  constructor(options: WebhookVerifierOptions) {
    this.currentSecret = options.currentSecret;
    this.previousSecret = options.previousSecret;
    this.maxSkewSeconds = options.maxSkewSeconds ?? 300;
    this.replayTtlSeconds = options.replayTtlSeconds ?? 600;
    this.replayStore = options.replayStore ?? new InMemoryReplayStore();
    this.headers = {
      signature: options.headerNames?.signature ?? 'x-webhook-signature',
      timestamp: options.headerNames?.timestamp ?? 'x-webhook-timestamp',
      eventId: options.headerNames?.eventId ?? 'x-webhook-id',
    };
  }

  async verify(rawBody: Buffer, headers: Record<string, string | string[] | undefined>): Promise<VerifyResult> {
    const signature = this.getHeader(headers, this.headers.signature);
    const timestampRaw = this.getHeader(headers, this.headers.timestamp);
    const eventId = this.getHeader(headers, this.headers.eventId);

    if (!signature || !timestampRaw) {
      return { ok: false, reason: 'missing_headers' };
    }

    const timestamp = Number(timestampRaw);
    if (!Number.isFinite(timestamp)) {
      return { ok: false, reason: 'invalid_timestamp' };
    }

    const nowSeconds = Math.floor(Date.now() / 1000);
    if (Math.abs(nowSeconds - timestamp) > this.maxSkewSeconds) {
      return { ok: false, reason: 'timestamp_skew' };
    }

    const signedPayload = Buffer.concat([
      Buffer.from(String(timestamp)),
      Buffer.from('.'),
      rawBody,
    ]);

    const valid = [this.currentSecret, this.previousSecret]
      .filter((secret): secret is string => Boolean(secret))
      .some((secret) => this.constantTimeMatch(signature, this.sign(secret, signedPayload)));

    if (!valid) {
      return { ok: false, reason: 'invalid_signature' };
    }

    if (eventId) {
      const replayKey = `webhook:${eventId}`;
      if (await this.replayStore.has(replayKey)) {
        return { ok: false, reason: 'replay' };
      }
      await this.replayStore.set(replayKey, this.replayTtlSeconds);
    }

    return { ok: true, eventId, timestamp };
  }

  private sign(secret: string, payload: Buffer): string {
    return crypto.createHmac('sha256', secret).update(payload).digest('hex');
  }

  private constantTimeMatch(received: string, expected: string): boolean {
    const a = Buffer.from(received, 'utf8');
    const b = Buffer.from(expected, 'utf8');
    if (a.length !== b.length) return false;
    return crypto.timingSafeEqual(a, b);
  }

  private getHeader(headers: Record<string, string | string[] | undefined>, name: string): string | undefined {
    const value = headers[name.toLowerCase()] ?? headers[name];
    return Array.isArray(value) ? value[0] : value;
  }
}

const app = express();

app.post(
  '/webhooks/provider',
  express.raw({ type: '*/*', limit: '1mb' }),
  async (req, res) => {
    const verifier = new WebhookVerifier({
      currentSecret: process.env.WEBHOOK_SECRET!,
      previousSecret: process.env.WEBHOOK_PREVIOUS_SECRET,
    });

    const result = await verifier.verify(req.body, req.headers as Record<string, string | string[] | undefined>);

    if (!result.ok) {
      return res.status(401).json({ error: result.reason });
    }

    const payload = JSON.parse(req.body.toString('utf8'));

    // Process only after verification succeeds.
    return res.status(202).json({ accepted: true, eventId: result.eventId, type: payload.type });
  },
);

app.listen(3000);
```

### Service design
- Verify against the **raw request body**, not parsed JSON.
- Sign `timestamp + "." + rawBody` with `HMAC-SHA256`.
- Reject requests with missing headers, invalid signatures, or stale timestamps.
- Store `eventId` with TTL to block replay attacks.
- Support **secret rotation** by checking current and previous secrets.
- Return `401` on verification failure, `202` after acceptance.

### Recommended API contract
Headers:
- `X-Webhook-Signature`: hex HMAC digest
- `X-Webhook-Timestamp`: unix seconds
- `X-Webhook-Id`: unique event id

### Production notes
- Use Redis instead of in-memory replay storage.
- Keep skew window small, usually `300s`.
- Cap body size.
- Log failure reason, but never log secrets or full signatures.
- Make downstream processing idempotent even after signature verification.

If you want, I can also provide this as a small standalone service with tests, OpenAPI spec, or an AWS Lambda version.

695.answer:
## URL Safety Scanner

### Goal
Classify a URL as **safe, suspicious, or malicious** using layered checks that are explainable, fast, and conservative.

### Core design
Build it as a pipeline with a final risk score and reasons:

1. **Normalize input**
   - Trim whitespace
   - Parse with a strict URL parser
   - Lowercase scheme/host
   - Convert IDN to punycode and keep original form
   - Remove default ports
   - Decode once for analysis, but preserve raw value

2. **Protocol checks**
   - Allow `http` and `https`
   - Flag or block `javascript:`, `data:`, `file:`, `blob:`, `ftp:` depending on product needs
   - Treat missing or malformed schemes as suspicious

3. **Domain analysis**
   - Extract TLD, registrable domain, subdomain
   - Detect raw IP hosts, especially public IPv4/IPv6
   - Flag lookalike domains:
     - homograph/Unicode spoofing
     - edit-distance similarity to protected brands
     - misleading subdomains like `paypal.com.attacker.tld`
   - Check suspicious patterns:
     - many subdomains
     - long random labels
     - excessive hyphens/numbers
     - newly seen domains if you have reputation data

4. **Path/query heuristics**
   - Detect credential bait words: `login`, `verify`, `reset`, `secure`, `wallet`, `invoice`
   - Flag encoded payloads, excessive escaping, or very long query strings
   - Detect dangerous file extensions or download bait where relevant
   - Look for URL shorteners and chained redirects

5. **Reputation and intelligence**
   - Safe browsing / blocklist providers
   - Internal denylist/allowlist
   - WHOIS/domain age if available
   - ASN / hosting reputation if available
   - Past verdict cache

6. **Content-aware checks** (optional, only if fetching is allowed)
   - Follow redirects with limits
   - Inspect landing page title, forms, password fields, brand impersonation
   - Detect file download responses
   - Sandbox fetches to avoid active content risk

7. **Scoring engine**
   - Assign weighted signals
   - Hard-fail on certain signals like `javascript:` or known malware domains
   - Example verdicts:
     - `0-24`: safe
     - `25-59`: suspicious
     - `60+`: malicious

### Recommended output schema
```json
{
  "input": "https://paypa1-secure-login.example.com/signin",
  "normalized_url": "https://paypa1-secure-login.example.com/signin",
  "verdict": "suspicious",
  "score": 72,
  "reasons": [
    "Host resembles protected brand 'paypal'",
    "Contains credential-themed path 'signin'",
    "Subdomain structure may be deceptive"
  ],
  "signals": {
    "scheme": "https",
    "host_type": "domain",
    "uses_ip": false,
    "punycode": false,
    "shortener": false,
    "domain_age_days": null,
    "blocklist_match": false
  }
}
```

### Minimal architecture
- **Parser/Normalizer**
- **Rule Engine**
- **Reputation Adapters**
- **Scorer**
- **Explainer**
- **Cache**

### Safe default policy
- If parsing fails: `suspicious`
- If known malicious indicator hits: `malicious`
- If evidence is weak or unavailable: avoid claiming `safe`; prefer `low risk` or `no known issues`

### Example TypeScript skeleton
```ts
type Verdict = 'safe' | 'suspicious' | 'malicious';

type ScanResult = {
  input: string;
  normalizedUrl: string | null;
  verdict: Verdict;
  score: number;
  reasons: string[];
};

export function scanUrl(input: string): ScanResult {
  const reasons: string[] = [];
  let score = 0;
  let normalizedUrl: string | null = null;

  try {
    const url = new URL(input.trim());
    url.protocol = url.protocol.toLowerCase();
    url.hostname = url.hostname.toLowerCase();
    normalizedUrl = url.toString();

    if (!['http:', 'https:'].includes(url.protocol)) {
      score += 80;
      reasons.push(`Disallowed protocol: ${url.protocol}`);
    }

    const host = url.hostname;
    if (/^\d{1,3}(\.\d{1,3}){3}$/.test(host)) {
      score += 25;
      reasons.push('Host is a raw IPv4 address');
    }

    if (/(login|signin|verify|reset|secure|wallet)/i.test(url.pathname + url.search)) {
      score += 15;
      reasons.push('Credential-themed terms found in path or query');
    }

    if (host.split('.').length > 4) {
      score += 10;
      reasons.push('Excessive subdomain depth');
    }

    if (/[%]{3,}|%2f|%5c/i.test(url.pathname + url.search)) {
      score += 10;
      reasons.push('Heavy or suspicious encoding detected');
    }
  } catch {
    return {
      input,
      normalizedUrl: null,
      verdict: 'suspicious',
      score: 40,
      reasons: ['URL could not be parsed']
    };
  }

  const verdict: Verdict = score >= 60 ? 'malicious' : score >= 25 ? 'suspicious' : 'safe';

  return {
    input,
    normalizedUrl,
    verdict,
    score,
    reasons
  };
}
```

### Important cautions
- Heuristics alone create false positives.
- Reputation alone misses new threats.
- Do not auto-fetch unknown URLs unless the environment is isolated.
- "Safe" should mean **no known issues detected**, not guaranteed harmless.

