772.answer:
Prim’s algorithm builds a minimum spanning tree by starting from any node and repeatedly adding the cheapest edge that connects a visited node to an unvisited node. Using a min-priority queue makes each next-edge choice efficient.

### How it works
1. Pick any start node.
2. Mark it visited.
3. Push all outgoing edges from that node into a min-heap keyed by edge weight.
4. Repeatedly pop the smallest edge from the heap:
   - If it leads to an already visited node, skip it.
   - Otherwise, add its weight to the MST total, mark the new node visited, and push its outgoing edges.
5. Stop when all nodes are visited.

If the graph is disconnected, Prim’s algorithm from one start node only covers one connected component. For a full MST, the graph must be connected.

### Time complexity
With an adjacency list and priority queue:
- **Time:** `O((V + E) log E)`, commonly written as `O(E log V)`
- **Space:** `O(V + E)`

### Go implementation
```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to     int
	weight int
}

type Item struct {
	node   int
	weight int
}

type MinHeap []Item

func (h MinHeap) Len() int { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i].weight < h[j].weight }
func (h MinHeap) Swap(i, j int) { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x any) {
	*h = append(*h, x.(Item))
}

func (h *MinHeap) Pop() any {
	old := *h
	n := len(old)
	item := old[n-1]
	*h = old[:n-1]
	return item
}

// PrimMST returns the total weight of the minimum spanning tree.
// n is the number of nodes labeled [0, n-1].
func PrimMST(n int, graph [][]Edge) (int, bool) {
	if n == 0 {
		return 0, true
	}

	visited := make([]bool, n)
	pq := &MinHeap{}
	heap.Init(pq)

	totalWeight := 0
	visitedCount := 1
	visited[0] = true

	for _, e := range graph[0] {
		heap.Push(pq, Item{node: e.to, weight: e.weight})
	}

	for pq.Len() > 0 && visitedCount < n {
		item := heap.Pop(pq).(Item)
		if visited[item.node] {
			continue
		}

		visited[item.node] = true
		visitedCount++
		totalWeight += item.weight

		for _, e := range graph[item.node] {
			if !visited[e.to] {
				heap.Push(pq, Item{node: e.to, weight: e.weight})
			}
		}
	}

	if visitedCount != n {
		return 0, false
	}

	return totalWeight, true
}

func addUndirectedEdge(graph [][]Edge, u, v, w int) {
	graph[u] = append(graph[u], Edge{to: v, weight: w})
	graph[v] = append(graph[v], Edge{to: u, weight: w})
}

func main() {
	n := 5
	graph := make([][]Edge, n)

	addUndirectedEdge(graph, 0, 1, 2)
	addUndirectedEdge(graph, 0, 3, 6)
	addUndirectedEdge(graph, 1, 2, 3)
	addUndirectedEdge(graph, 1, 3, 8)
	addUndirectedEdge(graph, 1, 4, 5)
	addUndirectedEdge(graph, 2, 4, 7)
	addUndirectedEdge(graph, 3, 4, 9)

	total, ok := PrimMST(n, graph)
	if !ok {
		fmt.Println("graph is disconnected")
		return
	}

	fmt.Println("MST total weight:", total)
}
```

