778.answer:
AVL tree: a self-balancing binary search tree where for every node, the height difference between left and right subtrees is at most 1. After each insert, it updates heights and restores balance with rotations:

- **LL**: heavy on left-left → right rotation
- **RR**: heavy on right-right → left rotation
- **LR**: heavy on left-right → left rotation on left child, then right rotation
- **RL**: heavy on right-left → right rotation on right child, then left rotation

That keeps search/insert/delete at **O(log n)** in the balanced case.

```java
public class AVLTreeDemo {
    static class Node {
        int key;
        int height;
        Node left, right;

        Node(int key) {
            this.key = key;
            this.height = 1;
        }
    }

    static class AVLTree {
        private Node root;

        private int height(Node node) {
            return node == null ? 0 : node.height;
        }

        private int getBalance(Node node) {
            return node == null ? 0 : height(node.left) - height(node.right);
        }

        private void updateHeight(Node node) {
            node.height = 1 + Math.max(height(node.left), height(node.right));
        }

        private Node rightRotate(Node y) {
            Node x = y.left;
            Node t2 = x.right;

            x.right = y;
            y.left = t2;

            updateHeight(y);
            updateHeight(x);

            return x;
        }

        private Node leftRotate(Node x) {
            Node y = x.right;
            Node t2 = y.left;

            y.left = x;
            x.right = t2;

            updateHeight(x);
            updateHeight(y);

            return y;
        }

        public void insert(int key) {
            root = insert(root, key);
        }

        private Node insert(Node node, int key) {
            if (node == null) {
                return new Node(key);
            }

            if (key < node.key) {
                node.left = insert(node.left, key);
            } else if (key > node.key) {
                node.right = insert(node.right, key);
            } else {
                return node; // no duplicates
            }

            updateHeight(node);
            int balance = getBalance(node);

            // LL
            if (balance > 1 && key < node.left.key) {
                return rightRotate(node);
            }

            // RR
            if (balance < -1 && key > node.right.key) {
                return leftRotate(node);
            }

            // LR
            if (balance > 1 && key > node.left.key) {
                node.left = leftRotate(node.left);
                return rightRotate(node);
            }

            // RL
            if (balance < -1 && key < node.right.key) {
                node.right = rightRotate(node.right);
                return leftRotate(node);
            }

            return node;
        }

        public void printInOrder() {
            inOrder(root);
            System.out.println();
        }

        private void inOrder(Node node) {
            if (node == null) {
                return;
            }
            inOrder(node.left);
            System.out.print(node.key + " ");
            inOrder(node.right);
        }
    }

    public static void main(String[] args) {
        AVLTree tree = new AVLTree();
        int[] values = {10, 20, 30, 40, 50, 25};

        for (int value : values) {
            tree.insert(value);
        }

        System.out.print("In-order traversal: ");
        tree.printInOrder();
    }
}
```

For the insert sequence `{10, 20, 30, 40, 50, 25}`, the in-order output is:

```text
In-order traversal: 10 20 25 30 40 50
```

