A heap is a complete binary tree usually stored in an array.

- **Min-heap:** every parent is `<=` its children, so the smallest element is at the root.
- **Max-heap:** every parent is `>=` its children, so the largest element is at the root.
- **Complete binary tree:** all levels are full except possibly the last, which is filled left to right.

With array indexing:
- parent of `i` is `(i - 1) / 2`
- left child is `2 * i + 1`
- right child is `2 * i + 2`

Why heaps are useful:
- `peek` minimum: `O(1)`
- `insert`: `O(log n)`
- `extractMin`: `O(log n)`

Core idea:
- After inserting at the end, **bubble up** until heap order is restored.
- After removing the root, move the last element to the root and **bubble down**.

Here’s a simple min-heap in C++ with `insert`, `peek`, and `extractMin` operations:

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

class MinHeap {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent] <= heap[index]) break;
            swap(heap[parent], heap[index]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int n = heap.size();
        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < n && heap[left] < heap[smallest]) {
                smallest = left;
            }
            if (right < n && heap[right] < heap[smallest]) {
                smallest = right;
            }
            if (smallest == index) break;

            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int peek() const {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }
        return heap[0];
    }

    int extractMin() {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }

        int minValue = heap[0];
        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }

        return minValue;
    }

    bool empty() const {
        return heap.empty();
    }
};

int main() {
    MinHeap h;

    h.insert(10);
    h.insert(4);
    h.insert(15);
    h.insert(2);
    h.insert(8);

    cout << "Min: " << h.peek() << '\n';

    while (!h.empty()) {
        cout << h.extractMin() << " ";
    }
    cout << '\n';

    return 0;
}
```

Example output:
```text
Min: 2
2 4 8 10 15
```

