The Template Method pattern defines the skeleton of an algorithm in a base class, while letting subclasses override specific steps without changing the overall flow.

Use it when:
- multiple workflows share the same sequence of steps
- some steps vary by format or implementation
- you want to enforce process order in one place

For a data parser, the shared algorithm might be:
1. Load raw input
2. Validate it
3. Parse it
4. Post-process the result

The base class owns that sequence, and CSV/JSON parsers customize only the variable parts.

```csharp
using System;
using System.Collections.Generic;
using System.Text.Json;

public abstract class DataParser
{
    public List<Dictionary<string, string>> ParseData(string input)
    {
        string raw = Load(input);
        Validate(raw);
        var records = Parse(raw);
        return PostProcess(records);
    }

    protected virtual string Load(string input)
    {
        return input?.Trim() ?? string.Empty;
    }

    protected virtual void Validate(string raw)
    {
        if (string.IsNullOrWhiteSpace(raw))
        {
            throw new ArgumentException("Input cannot be empty.");
        }
    }

    protected abstract List<Dictionary<string, string>> Parse(string raw);

    protected virtual List<Dictionary<string, string>> PostProcess(List<Dictionary<string, string>> records)
    {
        return records;
    }
}

public sealed class CsvDataParser : DataParser
{
    protected override List<Dictionary<string, string>> Parse(string raw)
    {
        var lines = raw.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        if (lines.Length < 2)
        {
            throw new FormatException("CSV must contain a header and at least one data row.");
        }

        var headers = lines[0].Split(',');
        var results = new List<Dictionary<string, string>>();

        for (int i = 1; i < lines.Length; i++)
        {
            var values = lines[i].Split(',');
            if (values.Length != headers.Length)
            {
                throw new FormatException($"Row {i} does not match header column count.");
            }

            var record = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            for (int j = 0; j < headers.Length; j++)
            {
                record[headers[j].Trim()] = values[j].Trim();
            }

            results.Add(record);
        }

        return results;
    }
}

public sealed class JsonDataParser : DataParser
{
    protected override List<Dictionary<string, string>> Parse(string raw)
    {
        using var document = JsonDocument.Parse(raw);

        if (document.RootElement.ValueKind != JsonValueKind.Array)
        {
            throw new FormatException("JSON input must be an array of objects.");
        }

        var results = new List<Dictionary<string, string>>();

        foreach (var element in document.RootElement.EnumerateArray())
        {
            if (element.ValueKind != JsonValueKind.Object)
            {
                throw new FormatException("Each JSON array item must be an object.");
            }

            var record = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var property in element.EnumerateObject())
            {
                record[property.Name] = property.Value.ToString();
            }

            results.Add(record);
        }

        return results;
    }
}

public static class Demo
{
    public static void Main()
    {
        string csv = @"
name,age,city
Alice,30,Paris
Bob,25,Berlin";

        string json = @"[
  { ""name"": ""Alice"", ""age"": 30, ""city"": ""Paris"" },
  { ""name"": ""Bob"", ""age"": 25, ""city"": ""Berlin"" }
]";

        DataParser csvParser = new CsvDataParser();
        DataParser jsonParser = new JsonDataParser();

        var csvRecords = csvParser.ParseData(csv);
        var jsonRecords = jsonParser.ParseData(json);

        Print("CSV", csvRecords);
        Print("JSON", jsonRecords);
    }

    private static void Print(string label, List<Dictionary<string, string>> records)
    {
        Console.WriteLine($"{label} results:");
        foreach (var record in records)
        {
            foreach (var pair in record)
            {
                Console.Write($"{pair.Key}={pair.Value} ");
            }
            Console.WriteLine();
        }
        Console.WriteLine();
    }
}
```

Why this is Template Method:
- `ParseData()` is the template method
- `Load()`, `Validate()`, and `PostProcess()` are shared/default steps
- `Parse()` is the required subclass-specific step
- clients use the same base-class API regardless of input format

If you want, I can also provide a version using strongly typed `Person` objects instead of `Dictionary<string, string>`.

