Middleware chaining runs a request through a sequence of functions, where each middleware can inspect or modify the request/response, stop the flow, or call `next()` to pass control to the next step. It’s useful for separating concerns like logging, auth, and business logic into small, composable units.

```js
class Response {
  constructor() {
    this.statusCode = 200;
    this.body = null;
    this.headers = {};
    this.finished = false;
  }

  status(code) {
    this.statusCode = code;
    return this;
  }

  json(data) {
    this.headers['content-type'] = 'application/json';
    this.body = JSON.stringify(data);
    this.finished = true;
    return this;
  }

  send(data) {
    this.body = data;
    this.finished = true;
    return this;
  }
}

function compose(middlewares) {
  return function run(req, res) {
    let index = -1;

    function dispatch(i) {
      if (i <= index) {
        return Promise.reject(new Error('next() called multiple times'));
      }

      index = i;
      const middleware = middlewares[i];

      if (!middleware || res.finished) {
        return Promise.resolve();
      }

      try {
        return Promise.resolve(
          middleware(req, res, () => dispatch(i + 1))
        );
      } catch (error) {
        return Promise.reject(error);
      }
    }

    return dispatch(0);
  };
}

const logger = async (req, res, next) => {
  console.log(`[LOG] ${req.method} ${req.path}`);
  await next();
};

const authenticate = async (req, res, next) => {
  const token = req.headers?.authorization;

  if (token !== 'Bearer secret-token') {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  req.user = { id: 1, role: 'admin' };
  await next();
};

const handler = async (req, res, next) => {
  res.json({
    message: 'Success',
    user: req.user,
    path: req.path,
  });

  await next();
};

const app = compose([logger, authenticate, handler]);

async function simulate(req) {
  const res = new Response();

  try {
    await app(req, res);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }

  return {
    statusCode: res.statusCode,
    headers: res.headers,
    body: res.body,
  };
}

(async () => {
  const authorized = await simulate({
    method: 'GET',
    path: '/profile',
    headers: { authorization: 'Bearer secret-token' },
  });

  const unauthorized = await simulate({
    method: 'GET',
    path: '/profile',
    headers: {},
  });

  console.log('Authorized response:', authorized);
  console.log('Unauthorized response:', unauthorized);
})();
```

How it works:
- `compose()` builds one pipeline from many middleware functions.
- Each middleware gets `(req, res, next)`.
- `logger` logs and passes control onward.
- `authenticate` blocks invalid requests or adds `req.user`.
- `handler` produces the final response.
- If a middleware ends the response without calling `next()`, the chain stops there.

