```ts
type OptionalQueryState<T = string> =
  | { kind: 'missing' }
  | { kind: 'empty' }
  | { kind: 'null' }
  | { kind: 'value'; value: T };

const DEFAULT_NULL_LIKE = new Set(['null', 'undefined']);

export function parseOptionalQueryParam(
  params: URLSearchParams,
  key: string,
  nullLikeValues: ReadonlySet<string> = DEFAULT_NULL_LIKE,
): OptionalQueryState {
  if (!params.has(key)) {
    return { kind: 'missing' };
  }

  const raw = params.get(key);

  if (raw === null) {
    return { kind: 'missing' };
  }

  if (raw === '') {
    return { kind: 'empty' };
  }

  const normalized = raw.trim().toLowerCase();
  if (nullLikeValues.has(normalized)) {
    return { kind: 'null' };
  }

  return { kind: 'value', value: raw };
}
```

Example behavior:

```ts
const cases = [
  ['', 'missing param entirely'],
  ['?q=', 'empty string'],
  ['?q=null', 'explicit null-like'],
  ['?q=no', 'real value'],
];

for (const [query, label] of cases) {
  const parsed = parseOptionalQueryParam(new URLSearchParams(query), 'q');
  console.log(label, parsed);
}
```

Results:

- no `q` at all → `{ kind: 'missing' }`
- `?q=` → `{ kind: 'empty' }`
- `?q=null` or `?q=undefined` → `{ kind: 'null' }`
- `?q=no` → `{ kind: 'value', value: 'no' }`

