function deepClone(value, clones = new WeakMap()) {
  if (value === null || typeof value !== 'object') return value;

  if (clones.has(value)) return clones.get(value);

  if (value instanceof Date) {
    const result = new Date(value.getTime());
    clones.set(value, result);
    return result;
  }

  if (value instanceof RegExp) {
    const result = new RegExp(value.source, value.flags);
    result.lastIndex = value.lastIndex;
    clones.set(value, result);
    return result;
  }

  if (value instanceof Map) {
    const result = new Map();
    clones.set(value, result);
    for (const [key, val] of value) {
      result.set(deepClone(key, clones), deepClone(val, clones));
    }
    return result;
  }

  if (value instanceof Set) {
    const result = new Set();
    clones.set(value, result);
    for (const item of value) {
      result.add(deepClone(item, clones));
    }
    return result;
  }

  if (Array.isArray(value)) {
    const result = [];
    clones.set(value, result);
    for (const item of value) {
      result.push(deepClone(item, clones));
    }
    return result;
  }

  const result = Object.create(Object.getPrototypeOf(value));
  clones.set(value, result);

