          const [rk, rv] = rightEntries[i];
          if (deepEqual(lk, rk) && deepEqual(lv, rv)) {
            used[i] = true;
            continue outer;
          }
        }
        return false;
      }
      continue;
    }

    if (left instanceof Set || right instanceof Set) {
      if (!(left instanceof Set && right instanceof Set)) return false;
      if (left.size !== right.size) return false;

