function flattenObject(input) {
  const out = {};

  const escapeSegment = (segment) =>
    String(segment)
      .replace(/\\/g, "\\\\")
      .replace(/\./g, "\\.");

  const visit = (value, path) => {
    const key = path.join(".");

    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[key] = [];
        return;
      }
      value.forEach((item, index) => visit(item, [...path, escapeSegment(index)]));
      return;
    }

    if (value !== null && typeof value === "object") {
      const entries = Object.entries(value);
      if (entries.length === 0) {
        out[key] = {};
        return;
      }
      for (const [k, v] of entries) {
        visit(v, [...path, escapeSegment(k)]);
      }
      return;
    }

    out[key] = value;
  };

  for (const [k, v] of Object.entries(input)) {
    visit(v, [escapeSegment(k)]);
  }

  return out;
}
```

Escaping strategy:
- Use `.` as the path separator.
- Escape every literal `.` inside a key segment as `\.`.
- Escape every literal backslash as `\\` first.
- Join escaped segments with `.`.
- Array indices are emitted as normal path segments (`items.0`, `items.1`).
- Empty objects and empty arrays are preserved as terminal values.

