    emptyObj: {},
    emptyArr: [],
  },
  "x.y": {
    "z.w": 2,
  },
};

console.log(flattenObject(input));
// {
//   'a.b': 1,
//   'a.emptyObj': {},
//   'a.emptyArr': [],
//   'x\\.y.z\\.w': 2
// }
```

