function decimalStringToBinary(decimal) {
  if (typeof decimal !== 'string' || !/^\d+$/.test(decimal)) {
    throw new Error('Input must be a non-empty decimal string');
  }

  decimal = decimal.replace(/^0+(?!$)/, '');
  if (decimal === '0') return '0';

  const digits = decimal.split('').map(ch => ch.charCodeAt(0) - 48);
  const bits = [];

  while (!(digits.length === 1 && digits[0] === 0)) {
    let carry = 0;
    let write = 0;

    for (let i = 0; i < digits.length; i++) {
      const value = carry * 10 + digits[i];
      const q = (value / 2) | 0;
      carry = value % 2;
      if (write > 0 || q !== 0) {
        digits[write++] = q;
      }
    }

    digits.length = write || 1;
    if (write === 0) digits[0] = 0;
    bits.push(carry);
  }

  bits.reverse();
  return bits.join('');
}

// Example
console.log(decimalStringToBinary('123456789012345678901234567890'));
```

How it works:
- Store the decimal number as an array of base-10 digits.
- Repeatedly divide that array by 2.
- Each remainder is the next binary bit from least significant to most significant.
- Reverse the collected bits at the end.

Properties:
- Exact: no floating-point or bigint usage.
- Handles arbitrarily large inputs limited only by time/memory.
- Time complexity is roughly `O(n * number_of_bits)`; for very large inputs, you can optimize further by chunking digits into a larger base like `10^7` or `10^9`.

