JavaScript example:

```js
function normalizeDecimalString(s) {
  const m = s.match(/^([+-]?)(?:(\d+)(?:\.(\d*))?|\.(\d+))$/);
  if (!m) throw new Error(`Invalid decimal: ${s}`);

  let sign = m[1] === '-' ? -1 : 1;
  let intPart = m[2] ?? '0';
  let fracPart = m[3] ?? m[4] ?? '';

  intPart = intPart.replace(/^0+/, '') || '0';
  fracPart = fracPart.replace(/0+$/, '');

  if (intPart === '0' && fracPart === '') sign = 1;

  return { sign, intPart, fracPart };
}

function compareDecimalStrings(a, b) {
  const x = normalizeDecimalString(a);
  const y = normalizeDecimalString(b);

  if (x.sign !== y.sign) return x.sign - y.sign;

  const dir = x.sign;

  if (x.intPart.length !== y.intPart.length) {
    return (x.intPart.length - y.intPart.length) * dir;
  }

  if (x.intPart !== y.intPart) {
    return (x.intPart < y.intPart ? -1 : 1) * dir;
  }

  const n = Math.max(x.fracPart.length, y.fracPart.length);
  for (let i = 0; i < n; i++) {
    const dx = x.fracPart[i] ?? '0';
    const dy = y.fracPart[i] ?? '0';
    if (dx !== dy) return (dx < dy ? -1 : 1) * dir;
  }

  return 0;
}

function sortDecimalStrings(values) {
  return [...values].sort(compareDecimalStrings);
}

// If you want a stable total order among numerically equal values:
function sortDecimalStringsWithTieBreak(values) {
  return [...values].sort((a, b) => compareDecimalStrings(a, b) || a.localeCompare(b));
}
```

Example:

```js
