function roundDecimalStringBankers(value, places) {
  if (!Number.isInteger(places) || places < 0) {
    throw new RangeError('places must be a non-negative integer');
  }
  if (typeof value !== 'string') {
    throw new TypeError('value must be a string');
  }

  const match = value.trim().match(/^([+-]?)(\d+)(?:\.(\d*))?$/);
  if (!match) {
    throw new Error('invalid decimal string');
  }

  const [, sign, intPartRaw, fracRaw = ''] = match;
  const negative = sign === '-';
  const digits = intPartRaw + fracRaw;
  const scale = fracRaw.length;

  let n = BigInt(digits || '0');
  const shift = scale - places;

  if (shift <= 0) {
    const zeros = '0'.repeat(-shift);
    return `${negative && n !== 0n ? '-' : ''}${intPartRaw}.${fracRaw}${zeros}`.replace(/\.$/, '');
  }

  const divisor = 10n ** BigInt(shift);
  const quotient = n / divisor;
  const remainder = n % divisor;
  const half = divisor / 2n;

  let rounded = quotient;
  if (remainder > half) {
    rounded += 1n;
  } else if (remainder === half) {
    if ((quotient % 2n) !== 0n) {
      rounded += 1n;
    }
  }

  let s = rounded.toString();
  if (places === 0) {
    return `${negative && rounded !== 0n ? '-' : ''}${s}`;
  }

  if (s.length <= places) {
    s = s.padStart(places + 1, '0');
  }

  const i = s.slice(0, -places);
  const f = s.slice(-places);
  return `${negative && rounded !== 0n ? '-' : ''}${i}.${f}`;
}

// tests
console.log(roundDecimalStringBankers('1.25', 1)); // 1.2
console.log(roundDecimalStringBankers('1.35', 1)); // 1.4
console.log(roundDecimalStringBankers('1.15', 1)); // 1.2
console.log(roundDecimalStringBankers('2.5', 0));  // 2
