function ageInYears(birthdate, now) {
  const birth = new Date(birthdate);
  const current = new Date(now);

  const year = current.getUTCFullYear();
  const month = birth.getUTCMonth();
  const day = birth.getUTCDate();

  let birthdayThisYear = new Date(Date.UTC(year, month, day));

  // Handle Feb 29 birthdays in non-leap years
  if (month === 1 && day === 29 && birthdayThisYear.getUTCDate() !== 29) {
    birthdayThisYear = new Date(Date.UTC(year, 1, 28));
  }

  let age = year - birth.getUTCFullYear();

  if (current < birthdayThisYear) {
    age--;
  }

  return age;
}
```

### Notes
- `birthdate` should represent the person’s date of birth.
- `now` should be a timezone-aware timestamp like `"2026-03-29T23:59:59-04:00"`.
- Because `now` includes an offset, comparisons correctly handle moments just before or after local midnight.
- Leap-day birthdays are treated as occurring on **Feb 28** in non-leap years. If you want **Mar 1** instead, adjust that branch.

