function normalizeMinutes(value) {
  return ((value % 1440) + 1440) % 1440;
}

function compareLower(a, b) {
  if (a.minute !== b.minute) return a.minute - b.minute;
  if (a.inclusive === b.inclusive) return 0;
  return a.inclusive ? -1 : 1;
}

function compareUpper(a, b) {
  if (a.minute !== b.minute) return a.minute - b.minute;
  if (a.inclusive === b.inclusive) return 0;
  return a.inclusive ? 1 : -1;
}

function lowerAfterUpper(lower, upper) {
  if (lower.minute !== upper.minute) return lower.minute > upper.minute;
  return !lower.inclusive || !upper.inclusive;
}

function pointOverlapsRange(pointMinute, range) {
  for (const segment of expandRange(range)) {
    const lowerOk =
      pointMinute > segment.start.minute ||
      (pointMinute === segment.start.minute && segment.start.inclusive);
    const upperOk =
      pointMinute < segment.end.minute ||
      (pointMinute === segment.end.minute && segment.end.inclusive);
    if (lowerOk && upperOk) return true;
  }
  return false;
}

function buildSegments(range) {
  const start = normalizeMinutes(range.start);
  const end = normalizeMinutes(range.end);

  if (start < end) {
    return [[start, range.startInclusive, end, range.endInclusive]];
  }

  if (start > end) {
    return [
      [start, range.startInclusive, 1440, false],
      [0, true, end, range.endInclusive],
    ];
  }

  if (range.startInclusive && range.endInclusive) {
    return [[start, true, end, true]];
  }

  return [];
}

function expandRange(range) {
  return buildSegments(range)
    .map(([startMinute, startInclusive, endMinute, endInclusive]) => ({
      start: { minute: startMinute, inclusive: startInclusive },
      end: { minute: endMinute, inclusive: endInclusive },
    }))
    .filter(segment => !lowerAfterUpper(segment.start, segment.end));
}

function rangesOverlap(a, b) {
  const aStart = normalizeMinutes(a.start);
  const aEnd = normalizeMinutes(a.end);
  const bStart = normalizeMinutes(b.start);
  const bEnd = normalizeMinutes(b.end);

  if (aStart === aEnd && a.startInclusive && a.endInclusive) {
    return pointOverlapsRange(aStart, b);
  }

  if (bStart === bEnd && b.startInclusive && b.endInclusive) {
    return pointOverlapsRange(bStart, a);
  }

  const aSegments = expandRange(a);
  const bSegments = expandRange(b);

  for (const segA of aSegments) {
    for (const segB of bSegments) {
      const lower = compareLower(segA.start, segB.start) >= 0 ? segA.start : segB.start;
      const upper = compareUpper(segA.end, segB.end) <= 0 ? segA.end : segB.end;
      if (!lowerAfterUpper(lower, upper)) return true;
    }
  }

  return false;
}

// Example shape:
const intervalA = {
  start: 23 * 60,
  end: 2 * 60,
  startInclusive: true,
  endInclusive: false,
};

const intervalB = {
  start: 1 * 60,
  end: 1 * 60,
  startInclusive: true,
  endInclusive: true,
};

console.log(rangesOverlap(intervalA, intervalB)); // true
```

Assumptions:
- `start` and `end` are local-time minutes within a day; values are normalized mod 1440.
- A same-start-and-end range is:
  - a single instant if both ends are inclusive,
  - empty otherwise.
- A range spans midnight when `start > end`.

Quick cases:
- `[10:00, 10:00]` overlaps itself: `true`
- `(10:00, 10:00)` is empty: `false`
- `[23:00, 02:00)` overlaps `[01:00, 03:00)`: `true`
- `[23:00, 02:00)` overlaps `[02:00, 03:00)`: `false`
- `[23:00, 02:00]` overlaps `[02:00, 03:00)`: `true`

