```js
function binarySearchFirst(arr, target, compare = defaultCompare) {
  let left = 0;
  let right = arr.length - 1;
  let result = -1;

  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);
    const cmp = compare(arr[mid], target);

    if (cmp < 0) {
      left = mid + 1;
    } else {
      if (cmp === 0) result = mid;
      right = mid - 1;
    }
  }

  return result;
}

function defaultCompare(a, b) {
  if (a < b) return -1;
  if (a > b) return 1;
  return 0;
}
```

Comparison policy: `compare(element, target)` must return a negative value if `element < target`, positive if `element > target`, and `0` if they are equal. If duplicates exist, this returns the **first** matching index; otherwise `-1`.

