function parseAndValidateIPv6(input) {
  if (typeof input !== 'string') return null;

  const s = input.trim();
  if (!s || /[^0-9A-Fa-f:.]/.test(s)) return null;

  const hasIPv4 = s.includes('.');
  let ipv4Tail = null;
  let head = s;

  if (hasIPv4) {
    const lastColon = s.lastIndexOf(':');
    if (lastColon === -1) return null;
    const ipv4Part = s.slice(lastColon + 1);
    ipv4Tail = parseIPv4(ipv4Part);
    if (!ipv4Tail) return null;
    head = s.slice(0, lastColon) + ':ipv4';
  }

  if ((head.match(/::/g) || []).length > 1) return null;

  let parts;
  if (head.includes('::')) {
    const [left, right] = head.split('::');
    const leftParts = left ? left.split(':') : [];
    const rightParts = right ? right.split(':') : [];

    if (![...leftParts, ...rightParts].every(isHextetOrIPv4Marker)) return null;

    const present = leftParts.length + rightParts.length + (ipv4Tail ? 2 : 0);
    if (present >= 8) return null;

    const missing = 8 - present;
    parts = [
      ...leftParts,
      ...Array(missing).fill('0'),
      ...rightParts,
    ];
  } else {
    parts = head.split(':');
    if (!parts.every(isHextetOrIPv4Marker)) return null;
    const total = parts.length + (ipv4Tail ? 1 : 0);
    if (total !== 8) return null;
  }

  const nums = [];
  for (const part of parts) {
    if (part === 'ipv4') {
      nums.push((ipv4Tail[0] << 8) | ipv4Tail[1]);
      nums.push((ipv4Tail[2] << 8) | ipv4Tail[3]);
    } else {
      nums.push(parseInt(part || '0', 16));
    }
  }

  if (nums.length !== 8 || nums.some(n => !Number.isInteger(n) || n < 0 || n > 0xffff)) {
    return null;
  }

  return canonicalIPv6(nums);
}

function isHextetOrIPv4Marker(part) {
  return part === 'ipv4' || /^[0-9A-Fa-f]{1,4}$/.test(part);
}

function parseIPv4(s) {
  const parts = s.split('.');
  if (parts.length !== 4) return null;

  const nums = [];
  for (const part of parts) {
    if (!/^\d+$/.test(part)) return null;
    if (part.length > 1 && part[0] === '0') return null;
    const n = Number(part);
    if (n < 0 || n > 255) return null;
    nums.push(n);
  }
  return nums;
}

function canonicalIPv6(nums) {
  const hex = nums.map(n => n.toString(16));

  let bestStart = -1;
  let bestLen = 0;
  for (let i = 0; i < hex.length; ) {
    if (hex[i] !== '0') {
      i++;
      continue;
    }
    let j = i;
    while (j < hex.length && hex[j] === '0') j++;
    const len = j - i;
    if (len > bestLen && len >= 2) {
      bestStart = i;
      bestLen = len;
    }
    i = j;
  }

  if (bestStart === -1) return hex.join(':');

  const left = hex.slice(0, bestStart).join(':');
  const right = hex.slice(bestStart + bestLen).join(':');

  if (!left && !right) return '::';
  if (!left) return `::${right}`;
  if (!right) return `${left}::`;
  return `${left}::${right}`;
}

// Examples:
// parseAndValidateIPv6('2001:0DB8:0000:0000:0000:ff00:0042:8329')
// => '2001:db8::ff00:42:8329'
// parseAndValidateIPv6('::FFFF:192.168.0.1')
// => '::ffff:c0a8:1'
// parseAndValidateIPv6('2001::db8::1')
// => null
``` 

Returns the canonical IPv6 string for valid input, or `null` for invalid input.

