```js
class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

class LRUCache {
  constructor(capacity) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new Error('capacity must be a non-negative integer');
    }

    this.capacity = capacity;
    this.map = new Map();
    this.head = new Node(null, null); // most recent sentinel
    this.tail = new Node(null, null); // least recent sentinel
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.#moveToFront(node);
    return node.value;
  }

  set(key, value) {
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;
      this.#moveToFront(existing);
      return;
    }

    const node = new Node(key, value);
    this.map.set(key, node);
    this.#addToFront(node);

    if (this.map.size > this.capacity) {
      const lru = this.tail.prev;
      this.#remove(lru);
      this.map.delete(lru.key);
    }
  }

  has(key) {
    return this.map.has(key);
  }

  get size() {
    return this.map.size;
  }

  #moveToFront(node) {
    this.#remove(node);
    this.#addToFront(node);
  }

  #addToFront(node) {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  #remove(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
    node.prev = null;
    node.next = null;
  }
}

// Minimal verification
(function testLRUCache() {
  const assert = (condition, message) => {
    if (!condition) throw new Error(message);
  };

  // capacity 0
  const zero = new LRUCache(0);
  zero.set('a', 1);
  assert(zero.get('a') === undefined, 'capacity 0 should never store entries');
  assert(zero.size === 0, 'capacity 0 size should remain 0');

  // capacity 1 eviction
  const one = new LRUCache(1);
  one.set('a', 1);
  assert(one.get('a') === 1, 'capacity 1 should store first item');
  one.set('b', 2);
  assert(one.get('a') === undefined, 'capacity 1 should evict previous item');
  assert(one.get('b') === 2, 'capacity 1 should keep newest item');

  // same key repeatedly
  const repeat = new LRUCache(2);
  repeat.set('x', 1);
  repeat.set('x', 2);
  repeat.set('x', 3);
  assert(repeat.size === 1, 'repeated same-key inserts must not grow size');
  assert(repeat.get('x') === 3, 'same-key insert should overwrite value');

  repeat.set('y', 9);
  repeat.set('x', 4); // refresh x recency
  repeat.set('z', 10);
  assert(repeat.get('y') === undefined, 'updated key should become most recent');
  assert(repeat.get('x') === 4, 'updated key should remain present');
  assert(repeat.get('z') === 10, 'new key should be present');

  // falsy values: 0 and empty string
  const falsy = new LRUCache(2);
  falsy.set('n', 0);
  falsy.set('s', '');
  assert(falsy.get('n') === 0, 'should store numeric 0 correctly');
  assert(falsy.get('s') === '', 'should store empty string correctly');

  console.log('All tests passed');
})();
```

This handles the edge cases correctly:
- `capacity = 0`: nothing is ever stored
- `capacity = 1`: every new distinct key evicts the previous one
- repeated `set` on the same key updates in place without increasing size
- stored falsy values like `0` and `''` work because presence is checked by node existence, not truthiness of the value

