```js
function topologicalSort(graph) {
  const state = new Map(); // 0 = unvisited, 1 = visiting, 2 = visited
  const order = [];
  const stack = [];
  const stackIndex = new Map();

  const nodes = new Set();
  for (const [node, deps] of Object.entries(graph)) {
    nodes.add(node);
    for (const dep of deps) nodes.add(dep);
  }

  function visit(node) {
    const nodeState = state.get(node) || 0;
    if (nodeState === 2) return null;
    if (nodeState === 1) {
      const start = stackIndex.get(node);
      return [...stack.slice(start), node];
    }

    state.set(node, 1);
    stackIndex.set(node, stack.length);
    stack.push(node);

    const deps = graph[node] || [];
    for (const dep of deps) {
      const cycle = visit(dep);
      if (cycle) return cycle;
    }

    stack.pop();
    stackIndex.delete(node);
    state.set(node, 2);
    order.push(node);
    return null;
  }

  for (const node of nodes) {
    if ((state.get(node) || 0) !== 0) continue;
    const cycle = visit(node);
    if (cycle) {
      return { ok: false, cycle };
    }
  }

  return { ok: true, order };
}

// Examples:
console.log(topologicalSort({
  A: ['B', 'C'],
  B: ['D'],
  C: ['D'],
  D: [],
  E: ['F'],
  F: []
}));
// { ok: true, order: [ 'D', 'B', 'C', 'A', 'F', 'E' ] } (one valid order)

console.log(topologicalSort({ A: ['A'] }));
// { ok: false, cycle: [ 'A', 'A' ] }

console.log(topologicalSort({
  A: ['B'],
  B: ['C'],
  C: ['A']
}));
// { ok: false, cycle: [ 'A', 'B', 'C', 'A' ] }
```

Notes:
- Handles self-loops naturally: `A -> A` returns `["A", "A"]`.
- Handles disconnected components by iterating all discovered nodes.
- Handles nodes that appear only as dependencies by adding them to `nodes`.
- Returns one exact detected cycle path when a cycle exists.

