function dedupeDeep(items) {
  const seen = new Set();
  const out = [];

  for (const item of items) {
    const key = canonicalize(item);
    if (!seen.has(key)) {
      seen.add(key);
      out.push(item);
    }
  }

  return out;
}

function canonicalize(value) {
  if (value === null) return 'null';

  const type = typeof value;

  if (type === 'string') {
    return `str:${JSON.stringify(value.normalize('NFC'))}`;
  }

  if (type === 'number') {
    if (Number.isNaN(value)) return 'num:NaN';
    if (!Number.isFinite(value)) return `num:${value}`;
    return `num:${Object.is(value, -0) ? '0' : String(value)}`;
  }

  if (type === 'boolean') return `bool:${value}`;
  if (type === 'bigint') return `bigint:${value}`;
  if (type === 'undefined') return 'undefined';

  if (Array.isArray(value)) {
    return `arr:[${value.map(canonicalize).join(',')}]`;
  }

  if (type === 'object') {
    const keys = Object.keys(value).sort();
    return `obj:{${keys
      .map((key) => `${JSON.stringify(key)}:${canonicalize(value[key])}`)
      .join(',')}}`;
  }

  throw new TypeError(`Unsupported value type: ${type}`);
}

// example
const input = [
  { b: 2, a: 'e\u0301' },
  { a: '\u00E9', b: 2.0 },
  { a: 'x', b: [1, { y: 3 }] },
  { b: [1.0, { y: 3 }], a: 'x' }
];

console.log(dedupeDeep(input));
```

This works by turning each object into a canonical string:
- object keys are sorted
- strings are Unicode-normalized with `NFC`
- numbers use a normalized representation, so equivalent numeric values dedupe together
- arrays keep order

