```js
function serializeFormData(input) {
  const pairs = [];

  const encodeKeyPart = (part) =>
    encodeURIComponent(String(part)).replace(/%5B/g, '[').replace(/%5D/g, ']');

  const buildKey = (path) => {
    if (path.length === 0) return '';
    return path
      .map((part, index) => (index === 0 ? encodeKeyPart(part) : `[${encodeKeyPart(part)}]`))
      .join('');
  };

  const pushPair = (path, value) => {
    const key = buildKey(path);
    const normalized = value == null ? '' : String(value);
    pairs.push(`${key}=${encodeURIComponent(normalized)}`);
  };

  const visit = (value, path) => {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        pushPair(path, '');
        return;
      }

      for (const item of value) {
        visit(item, [...path, '']);
      }
      return;
    }

    if (value && typeof value === 'object') {
      const entries = Object.entries(value);

      if (entries.length === 0) {
        pushPair(path, '');
        return;
      }

      for (const [key, nestedValue] of entries) {
        visit(nestedValue, [...path, key]);
      }
      return;
    }

    pushPair(path, value);
  };

  for (const [key, value] of Object.entries(input)) {
    visit(value, [key]);
  }

  return pairs.join('&');
}
```

