  name: '',
  active: false,
  tags: ['a', 'b'],
  meta: { age: null, subscribed: true },
  'filter[status]': 'open'
});
// name=&active=false&tags[]=a&tags[]=b&meta[age]=&meta[subscribed]=true&filter%5Bstatus%5D=open
```

