function evaluateExpression(input) {
  let i = 0;
  const s = input;

  function isDigit(ch) {
    return ch >= '0' && ch <= '9';
  }

  const values = [];
  const ops = [];
  let expectValue = true;

  function applyTop() {
    if (values.length < 2 || ops.length === 0) {
      throw new Error('Malformed expression');
    }
    const b = values.pop();
    const a = values.pop();
    const op = ops.pop();
    if (op === '+') values.push(a + b);
    else if (op === '-') values.push(a - b);
    else if (op === '*') values.push(a * b);
    else if (op === '/') values.push(a / b);
    else throw new Error('Malformed expression');
  }

  function precedence(op) {
    return op === '+' || op === '-' ? 1 : op === '*' || op === '/' ? 2 : 0;
  }

  while (i < s.length) {
    const ch = s[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch === '(') {
      if (!expectValue) {
        throw new Error('Malformed expression');
      }
      ops.push(ch);
      i++;
      continue;
    }

    if (ch === ')') {
      if (expectValue) {
        throw new Error('Malformed expression');
      }
      while (ops.length && ops[ops.length - 1] !== '(') {
        applyTop();
      }
      if (ops.length === 0) {
        throw new Error('Malformed expression');
      }
      ops.pop();
      i++;
      continue;
    }

    if (isDigit(ch)) {
      if (!expectValue) {
        throw new Error('Malformed expression');
      }
      let num = 0;
      while (i < s.length && isDigit(s[i])) {
        num = num * 10 + (s.charCodeAt(i) - 48);
        i++;
      }
      values.push(num);
      expectValue = false;
      continue;
    }

    if (ch === '+' || ch === '-' || ch === '*' || ch === '/') {
      if (expectValue) {
        throw new Error('Malformed expression');
      }
      while (
        ops.length &&
        ops[ops.length - 1] !== '(' &&
        precedence(ops[ops.length - 1]) >= precedence(ch)
      ) {
        applyTop();
      }
      ops.push(ch);
      expectValue = true;
      i++;
      continue;
    }

    throw new Error('Malformed expression');
  }

  if (expectValue) {
    throw new Error('Malformed expression');
  }

  while (ops.length) {
    if (ops[ops.length - 1] === '(') {
      throw new Error('Malformed expression');
    }
    applyTop();
  }

  if (values.length !== 1) {
    throw new Error('Malformed expression');
  }

  return values[0];
}
```

This is iterative, so it handles nesting depth 50,000 without recursion overflow.

Rejected as malformed:
- `()`
- `(1+)`
- `1++2`
- `1+*2`
- `( )`
- `1(2+3)`
- `1 2`

