import { createHash } from 'node:crypto';

export function stableJsonHash(value, algorithm = 'sha256') {
  const seen = new Map();
  let nextId = 0;

  const normalize = (input) => {
    if (input === null) return null;

    const type = typeof input;

    if (type === 'number') {
      if (Number.isNaN(input)) return { $type: 'number', value: 'NaN' };
      if (!Number.isFinite(input)) return { $type: 'number', value: String(input) };
      if (Object.is(input, -0)) return { $type: 'number', value: '-0' };
      return input;
    }

    if (type === 'bigint') {
      return { $type: 'bigint', value: input.toString() };
    }

    if (type === 'undefined') {
      return { $type: 'undefined' };
    }

    if (type === 'function') {
      return { $type: 'function' };
    }

    if (type === 'symbol') {
      return { $type: 'symbol', value: String(input) };
    }

    if (type !== 'object') {
      return input;
    }

    if (seen.has(input)) {
      return { $ref: seen.get(input) };
    }

    const id = `#${nextId++}`;
    seen.set(input, id);

    if (Array.isArray(input)) {
      return {
        $id: id,
        $type: 'array',
        value: input.map(normalize),
      };
    }

    if (input instanceof Date) {
      return {
        $id: id,
        $type: 'date',
        value: input.toISOString(),
      };
    }

    if (input instanceof RegExp) {
      return {
        $id: id,
        $type: 'regexp',
        value: input.toString(),
      };
    }

    if (input instanceof Set) {
      const items = Array.from(input, normalize).sort(compareNormalized);
      return {
        $id: id,
        $type: 'set',
        value: items,
      };
    }

    if (input instanceof Map) {
      const entries = Array.from(input, ([k, v]) => [normalize(k), normalize(v)]);
      entries.sort((a, b) => {
        const ak = stringifyNormalized(a[0]);
        const bk = stringifyNormalized(b[0]);
        if (ak !== bk) return ak < bk ? -1 : 1;
        const av = stringifyNormalized(a[1]);
        const bv = stringifyNormalized(b[1]);
        return av < bv ? -1 : av > bv ? 1 : 0;
      });
      return {
        $id: id,
        $type: 'map',
        value: entries,
      };
    }

    const keys = Object.keys(input).sort();
    const out = { $id: id, $type: 'object' };
    for (const key of keys) {
      out[key] = normalize(input[key]);
    }
    return out;
  };

  const stringifyNormalized = (input) => JSON.stringify(input);

  const compareNormalized = (a, b) => {
    const sa = stringifyNormalized(a);
    const sb = stringifyNormalized(b);
    return sa < sb ? -1 : sa > sb ? 1 : 0;
  };

  const canonical = JSON.stringify(normalize(value));
  return createHash(algorithm).update(canonical).digest('hex');
}
```

