function diffJson(a, b) {
  const changes = [];
  const seenA = new WeakMap();
  const seenB = new WeakMap();

  walk(a, b, []);

  return changes;

  function walk(left, right, path) {
    if (Object.is(left, right)) return;

    const leftIsArray = Array.isArray(left);
    const rightIsArray = Array.isArray(right);
    const leftIsObj = isObject(left);
    const rightIsObj = isObject(right);

    if (leftIsObj || leftIsArray || rightIsObj || rightIsArray) {
      const leftCycle = getCyclePath(seenA, left);
      const rightCycle = getCyclePath(seenB, right);

      if (leftCycle || rightCycle) {
        if (leftCycle !== rightCycle) {
          changes.push({
            path: formatPath(path),
            type: "circular_change",
            before: leftCycle ?? left,
            after: rightCycle ?? right,
          });
        }
        return;
      }

      remember(seenA, left, path);
      remember(seenB, right, path);
    }

    const leftType = kindOf(left);
    const rightType = kindOf(right);

    if (leftType !== rightType) {
      changes.push({
        path: formatPath(path),
        type: "type_change",
        beforeType: leftType,
        afterType: rightType,
        before: left,
        after: right,
      });
      return;
    }

    if (leftIsArray && rightIsArray) {
      diffArray(left, right, path);
      return;
    }

    if (leftIsObj && rightIsObj) {
      diffObject(left, right, path);
      return;
    }

    changes.push({
      path: formatPath(path),
      type: "change",
      before: left,
      after: right,
    });
  }

  function diffObject(left, right, path) {
    const keys = new Set([...Reflect.ownKeys(left), ...Reflect.ownKeys(right)]);

    for (const key of keys) {
      const leftHas = Object.prototype.hasOwnProperty.call(left, key);
      const rightHas = Object.prototype.hasOwnProperty.call(right, key);
      const nextPath = path.concat(key);

      if (!leftHas && rightHas) {
        changes.push({
          path: formatPath(nextPath),
          type: "add",
          after: right[key],
        });
        continue;
      }

      if (leftHas && !rightHas) {
        changes.push({
          path: formatPath(nextPath),
          type: "delete",
          before: left[key],
        });
        continue;
      }

      walk(left[key], right[key], nextPath);
    }
  }

  function diffArray(left, right, path) {
    const max = Math.max(left.length, right.length);

    for (let i = 0; i < max; i++) {
      const leftHas = i in left;
      const rightHas = i in right;
      const nextPath = path.concat(i);

      if (!leftHas && rightHas) {
        changes.push({
          path: formatPath(nextPath),
          type: "add",
          after: right[i],
        });
        continue;
      }

      if (leftHas && !rightHas) {
        changes.push({
          path: formatPath(nextPath),
          type: "delete",
          before: left[i],
        });
        continue;
      }

      walk(left[i], right[i], nextPath);
    }

    if (left.length !== right.length) {
      changes.push({
        path: formatPath(path.concat("length")),
        type: "change",
        before: left.length,
        after: right.length,
      });
    }
  }

  function isObject(value) {
    return value !== null && typeof value === "object" && !Array.isArray(value);
  }

  function kindOf(value) {
    if (Array.isArray(value)) return "array";
    if (value === null) return "null";
    return typeof value;
  }

  function remember(seen, value, path) {
    if (value && typeof value === "object") {
      seen.set(value, formatPath(path));
    }
  }

  function getCyclePath(seen, value) {
    if (value && typeof value === "object") {
      return seen.get(value) ?? null;
    }
    return null;
  }

  function formatPath(path) {
    if (path.length === 0) return "$";

    let out = "$";
    for (const part of path) {
      if (typeof part === "number") {
        out += `[${part}]`;
      } else if (part === "length") {
        out += ".length";
      } else if (/^[A-Za-z_$][A-Za-z0-9_$]*$/.test(String(part))) {
        out += `.${String(part)}`;
      } else {
        out += `[${JSON.stringify(String(part))}]`;
      }
    }
    return out;
  }
}
```

